import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';

function TaskList() {
  const [tasks, setTasks] = useState([]);

  useEffect(() => {
    fetch('/api/tasks/')
      .then(res => res.json())
      .then(setTasks);
  }, []);

  return (
    <div>
      <h1>Open Tasks</h1>
      <ul>
        {tasks.map(task => (
          <li key={task.id}>
            <Link to={`/task/${task.id}`}>{task.description}</Link> - {task.status}
          </li>
        ))}
      </ul>
      <Link to="/dashboard">Go to Dashboard</Link>
    </div>
  );
}

export default TaskList;
